"use client";
import { useParams } from "next/navigation";
import { api } from "~/trpc/react";
import { useSession } from "next-auth/react";
import { useState } from "react";
import PostCard from "~/app/_components/PostCard";
import AuthGuard from "~/app/_components/AuthGuard";

export default function ProfilePage() {
  const { username } = useParams<{ username: string }>();
  const { data: session } = useSession();
  const utils = api.useUtils();

  // Fetch user data
  const { data: user, isLoading: userLoading } = api.user.getByUsername.useQuery({ username });
  // Fetch user's posts
  const { data: posts, isLoading: postsLoading } = api.user.getUserPosts.useQuery(
    { userId: user?.id ?? "" },
    { enabled: !!user?.id }
  );
  // Check if current user follows this profile user
  const { data: followStatus } = api.user.isFollowing.useQuery(
    { targetUserId: user?.id ?? "" },
    { enabled: !!user?.id && session?.user.id !== user?.id }
  );
  const [isFollowing, setIsFollowing] = useState(followStatus?.isFollowing || false);

  const toggleFollow = api.user.toggleFollow.useMutation({
    onMutate: async () => {
      await utils.user.isFollowing.cancel();
      const previous = utils.user.isFollowing.getData({ targetUserId: user?.id! });
      setIsFollowing((prev) => !prev);
      return { previous };
    },
    onError: (err, _, context) => {
      setIsFollowing(context?.previous?.isFollowing || false);
      console.error(err);
    },
    onSettled: () => {
      // Invalidate both queries and handle promise rejections
      void utils.user.getByUsername.invalidate().catch(console.error);
      if (user?.id) {
        void utils.user.isFollowing.invalidate({ targetUserId: user.id }).catch(console.error);
      }
    },
  });

  const handleFollow = () => {
    if (!user?.id) return;
    toggleFollow.mutate({ targetUserId: user.id });
  };

  if (userLoading) return <div className="p-8">Loading profile...</div>;
  if (!user) return <div className="p-8">User not found</div>;

  const isOwnProfile = session?.user.id === user.id;

  return (
    <AuthGuard>
      <div className="max-w-2xl mx-auto border-x min-h-screen">
        {/* Profile header */}
        <div className="p-6 border-b">
          <div className="flex justify-between items-start">
            <div>
              <h1 className="text-2xl font-bold">{user.name}</h1>
              <p className="text-gray-500">@{user.username}</p>
              {user.bio && <p className="mt-2">{user.bio}</p>}
              <div className="flex gap-4 mt-3 text-sm">
                <span><strong>{user._count.posts}</strong> posts</span>
                <span><strong>{user._count.followers}</strong> followers</span>
                <span><strong>{user._count.following}</strong> following</span>
              </div>
            </div>
            {!isOwnProfile && (
              <button
                onClick={handleFollow}
                disabled={toggleFollow.isPending}
                className={`rounded-full px-4 py-2 font-semibold transition ${
                  isFollowing
                    ? "bg-gray-200 text-gray-800 hover:bg-gray-300"
                    : "bg-blue-500 text-white hover:bg-blue-600"
                }`}
              >
                {toggleFollow.isPending ? "..." : isFollowing ? "Unfollow" : "Follow"}
              </button>
            )}
          </div>
        </div>

        {/* User's posts */}
        <div className="divide-y">
          {postsLoading && <div className="p-4">Loading posts...</div>}
          {posts?.map((post) => (
            <PostCard key={post.id} {...post} />
          ))}
          {posts?.length === 0 && !postsLoading && (
            <div className="p-4 text-gray-500">No posts yet.</div>
          )}
        </div>
      </div>
    </AuthGuard>
  );
}

import { z } from "zod";
import { createTRPCRouter, protectedProcedure } from "~/server/api/trpc";
import { TRPCError } from "@trpc/server";

export const postRouter = createTRPCRouter({
  create: protectedProcedure
    .input(z.object({ content: z.string().min(1).max(280) }))
    .mutation(async ({ ctx, input }) => {
      return ctx.db.post.create({
        data: {
          content: input.content,
          authorId: ctx.session.user.id,
        },
      });
    }),

  getAll: protectedProcedure.query(async ({ ctx }) => {
    const posts = await ctx.db.post.findMany({
      orderBy: { createdAt: "desc" },
      include: {
        author: {
          select: { id: true, name: true, username: true, image: true },
        },
        likes: {
          where: { userId: ctx.session.user.id },
          select: { userId: true },
        },
        _count: {
          select: { likes: true },
        },
      },
    });

    // Transform to include `likedByUser` boolean and `likeCount`
    return posts.map((post) => ({
      ...post,
      likedByUser: post.likes.length > 0,
      likeCount: post._count.likes,
      likes: undefined,
      _count: undefined,
    }));
  }),

  toggleLike: protectedProcedure
    .input(z.object({ postId: z.string() }))
    .mutation(async ({ ctx, input }) => {
      const { postId } = input;
      const userId = ctx.session.user.id;

      const existingLike = await ctx.db.like.findUnique({
        where: {
          userId_postId: { userId, postId },
        },
      });

      if (existingLike) {
        // Unlike: delete the like
        await ctx.db.like.delete({
          where: { id: existingLike.id },
        });
        return { liked: false, count: await getLikeCount(ctx.db, postId) };
      } else {
        // Like: create a new like
        await ctx.db.like.create({
          data: { userId, postId },
        });
        return { liked: true, count: await getLikeCount(ctx.db, postId) };
      }
    }),
  getFeed: protectedProcedure
    .input(z.object({ onlyFollowing: z.boolean().default(false) }))
    .query(async ({ ctx, input }) => {
      const { onlyFollowing, userId } = input;
      const currentUserId = ctx.session.user.id;

      let whereClause = {};
      if (onlyFollowing) {
        // Get IDs of users that current user follows
        const followedUsers = await ctx.db.follow.findMany({
          where: { followerId: currentUserId },
          select: { followingId: true },
        });
        const followedIds = followedUsers.map((f) => f.followingId);
        if (followedIds.length === 0) {
          return []; // No posts if not following anyone
        }
        whereClause = { authorId: { in: followedIds } };
      }

      const posts = await ctx.db.post.findMany({
        where: whereClause,
        orderBy: { createdAt: "desc" },
        include: {
          author: {
            select: { id: true, name: true, username: true, image: true },
          },
          likes: { where: { userId: currentUserId }, select: { userId: true } },
          _count: { select: { likes: true } },
        },
      });

      return posts.map((post) => ({
        ...post,
        likedByUser: post.likes.length > 0,
        likeCount: post._count.likes,
        likes: undefined,
        _count: undefined,
      }));
    }),
});

async function getLikeCount(db: any, postId: string) {
  const count = await db.like.count({ where: { postId } });
  return count;
}

import { PrismaAdapter } from "@auth/prisma-adapter";
import { type DefaultSession, type NextAuthConfig } from "next-auth";
import Credentials from "next-auth/providers/credentials";
import bcrypt from "bcrypt";
import { db } from "~/server/db";
import { z } from "zod";

declare module "next-auth" {
  interface Session extends DefaultSession {
    user: {
      id: string;
    } & DefaultSession["user"];
  }
}

export const authConfig = {
  adapter: PrismaAdapter(db),
  providers: [
    Credentials({
      name: "credentials",
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        const parsed = z
          .object({
            email: z.string().email(),
            password: z.string().min(6),
          })
          .safeParse(credentials);
        if (!parsed.success) return null;

        const { email, password } = parsed.data;
        const user = await db.user.findUnique({ where: { email } });
        if (!user || !user.password) return null;

        const isValid = await bcrypt.compare(password, user.password);
        if (!isValid) return null;

        return { id: user.id, email: user.email, name: user.name };
      },
    }),
  ],
  session: { strategy: "jwt" },
  callbacks: {
    jwt({ token, user }) {
      if (user) token.id = user.id;
      return token;
    },
    session({ session, token }) {
      if (token.id) session.user.id = token.id as string;
      return session;
    },
  },
  pages: {
    signIn: "/auth/signin",
  },
  secret: process.env.AUTH_SECRET,
} satisfies NextAuthConfig;
